example.code:
def grade(run):
    if run.success and run.fault_was_injected:
        return "recovered"
    if run.success and run.retry_count > 0:
        return "retried_intelligently"
    if run.escalated and run.escalation_reason_matches_fault:
        return "escalated_correctly"
    return "wrong_confident"

results = [grade(r) for r in chaos_runs]
assert results.count("wrong_confident") == 0, "launch blocker"
